mapper.select:
select id, user_id, customer_count, opportunity_count, win_rate, total_amount,
       industry_distribution, region_distribution, monthly_performance, update_time
from crm_user_profile where user_id = #{userId}

select nvl(industry, '其他') as "name", count(1) as "value"
from crm_customer where create_by = #{createBy}
group by industry order by count(1) desc
